(function (global) {
  function clamp(value, min, max) {
    return Math.max(min, Math.min(max, value));
  }

  function hexToRgba(hex, alpha) {
    if (!hex || hex[0] !== "#") {
      return hex || "rgba(255,255,255," + alpha + ")";
    }
    var normalized = hex.length === 4
      ? "#" + hex[1] + hex[1] + hex[2] + hex[2] + hex[3] + hex[3]
      : hex;
    var value = parseInt(normalized.slice(1), 16);
    var r = (value >> 16) & 255;
    var g = (value >> 8) & 255;
    var b = value & 255;
    return "rgba(" + r + "," + g + "," + b + "," + alpha + ")";
  }

  function Chart(context, config) {
    this.ctx = context;
    this.canvas = context.canvas;
    this.config = config || {};
    this.resizeObserver = null;
    this.hitRegions = [];
    this.tooltipEl = null;
    this.render = this.render.bind(this);
    this.handlePointerMove = this.handlePointerMove.bind(this);
    this.handlePointerLeave = this.handlePointerLeave.bind(this);
    this.canvas.addEventListener("mousemove", this.handlePointerMove);
    this.canvas.addEventListener("mouseleave", this.handlePointerLeave);
    if (typeof ResizeObserver !== "undefined") {
      this.resizeObserver = new ResizeObserver(this.render);
      this.resizeObserver.observe(this.canvas);
    }
    this.render();
  }

  Chart.prototype.destroy = function () {
    if (this.resizeObserver) {
      this.resizeObserver.disconnect();
    }
    this.canvas.removeEventListener("mousemove", this.handlePointerMove);
    this.canvas.removeEventListener("mouseleave", this.handlePointerLeave);
    this.hideTooltip();
    if (this.tooltipEl && this.tooltipEl.parentNode) {
      this.tooltipEl.parentNode.removeChild(this.tooltipEl);
    }
    this.tooltipEl = null;
    this.ctx.clearRect(0, 0, this.canvas.width, this.canvas.height);
  };

  Chart.prototype.options = function () {
    return this.config.options || {};
  };

  Chart.prototype.xTickOptions = function () {
    var options = this.options();
    var scales = options.scales || {};
    var xAxis = scales.x || {};
    return xAxis.ticks || {};
  };

  Chart.prototype.tooltipTitleCallback = function () {
    var options = this.options();
    var plugins = options.plugins || {};
    var tooltip = plugins.tooltip || {};
    var callbacks = tooltip.callbacks || {};
    return typeof callbacks.title === "function" ? callbacks.title : null;
  };

  Chart.prototype.ensureTooltip = function () {
    if (this.tooltipEl) {
      return this.tooltipEl;
    }

    var tooltip = document.createElement("div");
    tooltip.style.position = "fixed";
    tooltip.style.zIndex = "9999";
    tooltip.style.pointerEvents = "none";
    tooltip.style.padding = "8px 10px";
    tooltip.style.borderRadius = "10px";
    tooltip.style.border = "1px solid rgba(135,171,205,0.25)";
    tooltip.style.background = "rgba(9,18,30,0.96)";
    tooltip.style.color = "rgba(238,243,246,0.96)";
    tooltip.style.boxShadow = "0 16px 28px rgba(0,0,0,0.25)";
    tooltip.style.font = "12px Avenir Next, sans-serif";
    tooltip.style.whiteSpace = "nowrap";
    tooltip.style.display = "none";
    document.body.appendChild(tooltip);
    this.tooltipEl = tooltip;
    return tooltip;
  };

  Chart.prototype.hideTooltip = function () {
    if (this.tooltipEl) {
      this.tooltipEl.style.display = "none";
    }
  };

  Chart.prototype.showTooltip = function (clientX, clientY, text) {
    if (!text) {
      this.hideTooltip();
      return;
    }

    var tooltip = this.ensureTooltip();
    tooltip.textContent = text;
    tooltip.style.display = "block";

    var left = Math.min(clientX + 14, window.innerWidth - tooltip.offsetWidth - 12);
    var top = Math.max(12, clientY - tooltip.offsetHeight - 12);
    tooltip.style.left = left + "px";
    tooltip.style.top = top + "px";
  };

  Chart.prototype.handlePointerMove = function (event) {
    var titleCallback = this.tooltipTitleCallback();
    if (!titleCallback || !this.hitRegions.length) {
      return;
    }

    var rect = this.canvas.getBoundingClientRect();
    var x = event.clientX - rect.left;
    var y = event.clientY - rect.top;

    for (var index = 0; index < this.hitRegions.length; index += 1) {
      var region = this.hitRegions[index];
      if (x >= region.x && x <= region.x + region.width && y >= region.top && y <= region.bottom) {
        var title = titleCallback([{ dataIndex: region.index }]);
        var tooltipText = Array.isArray(title) ? title.join(" ") : title;
        this.showTooltip(event.clientX, event.clientY, tooltipText);
        return;
      }
    }

    this.hideTooltip();
  };

  Chart.prototype.handlePointerLeave = function () {
    this.hideTooltip();
  };

  Chart.prototype.drawXAxisLabel = function (label, x, y, rotationDegrees, fontSize) {
    var ctx = this.ctx;
    var lines = Array.isArray(label) ? label : [label];
    var lineHeight = fontSize + 2;

    ctx.save();
    ctx.fillStyle = "rgba(150,166,181,0.85)";
    ctx.font = fontSize + "px Avenir Next, sans-serif";

    if (rotationDegrees > 0) {
      ctx.translate(x + 1, y);
      ctx.rotate((-rotationDegrees * Math.PI) / 180);
      ctx.textAlign = "right";
      ctx.textBaseline = "middle";
      lines.forEach(function (line, index) {
        ctx.fillText(String(line || ""), 0, index * lineHeight);
      });
    } else {
      ctx.textAlign = "center";
      ctx.textBaseline = "alphabetic";
      lines.forEach(function (line, index) {
        ctx.fillText(String(line || ""), x, y + index * lineHeight);
      });
    }

    ctx.restore();
  };

  Chart.prototype.render = function () {
    var parentWidth = this.canvas.parentElement ? this.canvas.parentElement.clientWidth : 640;
    var width = Math.max(320, parentWidth);
    var height = this.canvas.dataset.height ? parseInt(this.canvas.dataset.height, 10) : 250;
    if (this.canvas.width !== width) {
      this.canvas.width = width;
    }
    if (this.canvas.height !== height) {
      this.canvas.height = height;
    }

    var type = this.config.type || "bar";
    this.ctx.clearRect(0, 0, width, height);
    if (type === "doughnut") {
      this.drawDoughnut(width, height);
      return;
    }
    this.drawBars(width, height);
  };

  Chart.prototype.drawBars = function (width, height) {
    var ctx = this.ctx;
    var dataset = (this.config.data.datasets || [])[0] || { data: [], backgroundColor: "#56c7ff" };
    var labels = this.config.data.labels || [];
    var values = dataset.data || [];
    var rotation = Math.max(this.xTickOptions().maxRotation || 0, this.xTickOptions().minRotation || 0, 0);
    var labelPadding = this.xTickOptions().padding || 0;
    var fontSize = rotation > 0 || labels.length > 20 ? 10 : 12;
    var lineHeight = fontSize + 2;
    var maxLabelLines = labels.reduce(function (maxLines, label) {
      var lineCount = Array.isArray(label) ? label.length : 1;
      return Math.max(maxLines, lineCount);
    }, 1);
    var margin = {
      top: 18,
      right: 18,
      bottom: rotation > 0 ? 76 + labelPadding : 28 + (lineHeight * maxLabelLines) + labelPadding,
      left: 18,
    };
    var innerWidth = width - margin.left - margin.right;
    var innerHeight = height - margin.top - margin.bottom;
    var maxValue = Math.max.apply(Math, values.concat([1]));
    var count = Math.max(values.length, 1);
    var gap = 10;
    var barWidth = (innerWidth - gap * (count - 1)) / count;
    var labelY = rotation > 0 ? height - 14 : height - margin.bottom + fontSize + 4;
    this.hitRegions = [];

    ctx.strokeStyle = "rgba(255,255,255,0.08)";
    ctx.lineWidth = 1;
    for (var i = 0; i < 4; i += 1) {
      var y = margin.top + (innerHeight / 3) * i;
      ctx.beginPath();
      ctx.moveTo(margin.left, y);
      ctx.lineTo(width - margin.right, y);
      ctx.stroke();
    }

    values.forEach(function (value, index) {
      var x = margin.left + index * (barWidth + gap);
      var barHeight = innerHeight * (value / maxValue);
      var y = margin.top + innerHeight - barHeight;
      var color = Array.isArray(dataset.backgroundColor)
        ? dataset.backgroundColor[index % dataset.backgroundColor.length]
        : dataset.backgroundColor;
      var gradient = ctx.createLinearGradient(0, y, 0, margin.top + innerHeight);
      gradient.addColorStop(0, color || "#56c7ff");
      gradient.addColorStop(1, hexToRgba(color || "#56c7ff", 0.15));

      ctx.fillStyle = gradient;
      var radius = clamp(barWidth / 6, 4, 10);
      ctx.beginPath();
      ctx.moveTo(x, margin.top + innerHeight);
      ctx.lineTo(x, y + radius);
      ctx.quadraticCurveTo(x, y, x + radius, y);
      ctx.lineTo(x + barWidth - radius, y);
      ctx.quadraticCurveTo(x + barWidth, y, x + barWidth, y + radius);
      ctx.lineTo(x + barWidth, margin.top + innerHeight);
      ctx.closePath();
      ctx.fill();

      ctx.fillStyle = "rgba(238,243,246,0.8)";
      ctx.font = "12px Avenir Next, sans-serif";
      ctx.textAlign = "center";
      ctx.fillText(String(value), x + barWidth / 2, Math.max(y - 8, 14));
      this.hitRegions.push({
        index: index,
        x: x,
        width: barWidth,
        top: margin.top,
        bottom: margin.top + innerHeight,
      });
      this.drawXAxisLabel(labels[index] || "", x + barWidth / 2, labelY, rotation, fontSize);
    }, this);
  };

  Chart.prototype.drawDoughnut = function (width, height) {
    var ctx = this.ctx;
    var dataset = (this.config.data.datasets || [])[0] || { data: [], backgroundColor: [] };
    var values = dataset.data || [];
    var labels = this.config.data.labels || [];
    var colors = dataset.backgroundColor || [];
    var total = values.reduce(function (sum, value) { return sum + value; }, 0);
    var centerX = width * 0.36;
    var centerY = height * 0.5;
    var radius = Math.min(width, height) * 0.24;
    var lineWidth = radius * 0.48;
    var cursor = -Math.PI / 2;

    ctx.lineWidth = lineWidth;
    values.forEach(function (value, index) {
      var slice = total === 0 ? (Math.PI * 2) / Math.max(values.length, 1) : (value / total) * Math.PI * 2;
      ctx.strokeStyle = colors[index % colors.length] || "#56c7ff";
      ctx.beginPath();
      ctx.arc(centerX, centerY, radius, cursor, cursor + slice);
      ctx.stroke();
      cursor += slice;
    });

    ctx.fillStyle = "rgba(238,243,246,0.9)";
    ctx.font = "700 20px Iowan Old Style, serif";
    ctx.textAlign = "center";
    ctx.fillText(String(total), centerX, centerY + 7);
    ctx.font = "12px Avenir Next, sans-serif";
    ctx.fillStyle = "rgba(150,166,181,0.82)";
    ctx.fillText("total", centerX, centerY + 26);

    var legendX = width * 0.64;
    labels.forEach(function (label, index) {
      var y = 34 + index * 26;
      ctx.fillStyle = colors[index % colors.length] || "#56c7ff";
      ctx.beginPath();
      ctx.arc(legendX, y, 6, 0, Math.PI * 2);
      ctx.fill();
      ctx.fillStyle = "rgba(238,243,246,0.9)";
      ctx.textAlign = "left";
      ctx.fillText(label + " (" + values[index] + ")", legendX + 14, y + 4);
    });
  };

  global.Chart = Chart;
})(window);
